import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            String safeUserInput = StringEscapeUtils.escapeHtml4(userInput); // HTML-encode user input

            System.out.println("Hello, " + safeUserInput + "!"); // Display safely encoded user input

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
